var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS001L0059-01: <color=#ffd34c>【기록-015】 적성 평가</color>      ","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS001L0059-01：<color=#ffd34c>【記録-015】 適性評価</color>      ","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS001L0059-01: <color=#ffd34c>【Record-015】 Aptitude Evaluation</color>      ","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS001L0059-01: <color=#ffd34c>【記錄-015】 能力評價</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......그러니까 당신이 진짜 사장님이라는 거군요.","JPN":"……あなたが本当の社長なんですね。","ENG":"So you're the real CEO of this company?","TWN":"……所以，您才是真正的老闆吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 별로 놀라지 않는군. 의외인데?","JPN":"ああ、あまり驚かないんだな？","ENG":"Yes. You don't seem too surprised. That's unexpected.","TWN":"是的，妳不怎麼驚訝呢。明明很意外吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그야 처음부터 반자율형 원격조작 머신이라고 소개 받았으니까요.","JPN":"初めから、半自律型の遠隔操作マシーンだと紹介されていたので。","ENG":"Well, I was already told that you are a semi-autonomous remote controlled machine.","TWN":"那是因為從一開始，就聽到您介紹說，這是半自動型遠端操作機。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그렇지 않고서야 그 지독......","JPN":"でなければ、あのキツイ……","ENG":"If not, that nasty...","TWN":"不然的話，那位壞心的……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아니, 깐깐한 부사장님이 로봇을 상사로 모실 리가 없죠.","JPN":"いえ、気難しい副社長が、ロボットを上司として認めるわけがありません。","ENG":"Ahem, our particular Vice President would never accept a robot as her superior.","TWN":"不，是倔強的副總不可能會把機器人當成上司吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"배후에 누가 있을 거라는 추측 정도는 충분히 할 수 있습니다.","JPN":"背後に誰かがいるということくらいは、十分察することができます。","ENG":"I speculate that someone's controlling the robot with a remote.","TWN":"這樣就能推測出背後有誰在主使了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"눈치가 좋군.","JPN":"勘がいいな。","ENG":"You're good.","TWN":"觀察得不錯。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......버릇은 없지만요.","JPN":"……生意気ですが。","ENG":"Although a bit rude.","TWN":"……很沒禮貌就是了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"하하, 부사장님께는 내숭을 떨 필요가 없으니까요.","JPN":"はは、副社長の前では猫をかぶる必要がありませんから。","ENG":"Hah hah, it's because I don't have to be coy with you.","TWN":"哈哈，因為沒必要在副總面前裝乖啊。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"솔직한 모습을 보여드릴 만큼 존경하고 있다는 뜻으로 받아들여주시면 좋겠어요.","JPN":"ありのままの自分をお見せするほど、尊敬しているという意味です。","ENG":"Just think of it as a sign of respect I'm expressing towards you by being honest.","TWN":"我尊敬副總到會在副總面前展現出誠實的一面，希望您能理解成這個意思。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"나도 솔직하게 말해 주는 건데,","JPN":"私も正直に言いますけど、","ENG":"I'm being honest here as well.","TWN":"那我也就誠實地說吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"자네의 존경이 전혀 기쁘지가 않군.","JPN":"尊敬されても、まったく嬉しくないです。","ENG":"But your respect isn't very welcoming.","TWN":"對於妳的尊敬，我一點都不感到高興。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"대체 우리 회사에는 왜 이런 뒤틀린 사람들만 모여드는 건지......","JPN":"何でうちの会社には、こういうひねくれものばかり集まるのか……","ENG":"How come our company is always filled with twisted people?","TWN":"我們公司到底為什麼，只會聚集一些性格扭曲的人啊……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하아......","JPN":"はあ……","ENG":"*Sigh*","TWN":"唉……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그야 사장부터 아주 단단히 뒤틀려 있으니 그런 게 아니겠나?","JPN":"そりゃあ、社長がひねくれものだからな！","ENG":"Well, it's probably because the CEO is a twisted person to begin with. No?","TWN":"因為從老闆開始，就已經扭曲得很徹底了不是嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_LONG","text":{"KOREA":"경고! 경고! 강력한 감정적 충격이 감지되었습니다!","JPN":"警告！警告！感情のこもった、強力な衝撃が感知されました！","ENG":"Warning! Warning! A powerful emotional shock was detected!","TWN":"警告！ 警告！偵測到強力的情緒衝擊！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_LONG","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_LONG","text":{"KOREA":"메인보드에 손상이 갔을 수 있습니다!","JPN":"メインボードへの損傷が懸念されます！","ENG":"Possible damage inflicted to the mainboard!","TWN":"主機板可能已損壞！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_LONG","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그거 발로 차지 말게. 전에 말했지만 비싼 거야.","JPN":"それ、蹴らないでくれ。前にも言ったが高いんだ。","ENG":"Please don't kick that. As I said, it's really expensive.","TWN":"不要踢了。我之前說過，那個很貴的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그래서 무슨 일이시죠?","JPN":"それで、ご用件は？","ENG":"So, what brings you here?","TWN":"所以，叫我過來有什麼事嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"저 같은 말단 사원에게 감춰오던 얼굴을 직접 비추신 걸 보면 보통 일은 아닐 것 같은데요.","JPN":"私のような平社員に、今まで隠してた顔をお見せになったということは、ただ事ではなさそうですね。","ENG":"It must be something important for you to reveal your face to a minor employee like me.","TWN":"讓我這種底層員工直接看到您隱藏的面貌，應該不是普通的事情吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그야 자네에게 거절할 수 없는 제안을 하기 위해서지.","JPN":"君が決して断れない提案をするためだ。","ENG":"It's because I'm about to make you an offer you can't refuse.","TWN":"因為我要向妳提出一個妳無法拒絕的提案。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"제안을 수락할 경우 자네가 받을 수 있는 아주 파격적인 보상은 덤이고 말이야.","JPN":"この提案を受け入れる場合、君には破格の報酬を約束する。","ENG":"And if you accept the offer, you will get an exceptional reward as a bonus.","TWN":"如果接受提案，妳會額外獲得非常破格的報酬。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"블랙 네트워크에서 많이 듣던 이야기네요.","JPN":"ブラックネットワークでよく耳にする話ですね。","ENG":"I've heard a lot of those from the Dark Network.","TWN":"這種話在黑色網路上很常聽到呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그런 소리를 하는 의뢰주치고 제대로 된 일을 맡기는 경우는 없었는데 말이죠.","JPN":"こういう話をする人に限って、まともな依頼をしないもんです。","ENG":"Most of the clients who said something like that never gave me any proper work.","TWN":"說這種話的雇主，從來都不會給什麼像樣的委託。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 그럴 리가 있나. 여긴 그런 무뢰배들의 소굴이 아니라 엄연한 관리국 인증 기업이거든.","JPN":"はは、心配するな。ここはそんな無頼漢どもの巣窟じゃなく、管理局の認証を受けた正式な企業だ。","ENG":"Hah hah, we're not like them. Unlike that ruffian-filled dump, we are an official Administration-authorized company.","TWN":"哈哈，怎麼可能呢。這裡可不是那些無賴的巢窟，而是堂堂管理局認證的企業。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"특별한 일도 아니야.","JPN":"大したことじゃない。","ENG":"It's not that special really.","TWN":"不是什麼特別的事情。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그저 자네의 특기를 좀 더 적극적으로 발휘해 보면 되는 거지.","JPN":"ただ君の特技を、もう少し積極的に発揮するだけで十分だ。","ENG":"I was just thinking that you could be more active in utilizing your specialties.","TWN":"只是要妳更加積極地，發揮妳的特長就可以了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......제 특기가 뭔데요?","JPN":"……私の特技ですか？","ENG":"What are my specialties?","TWN":"……我的特長？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"친한척하기, 뒤통수치기, 재뿌리기, 뭐 그런 것들 아닌가?","JPN":"仲のいいふり、裏切り。あと、破滅させるのも得意だろう？","ENG":"Pretending to be friendly, backstabbing, and double-crossing?","TWN":"裝作很親切的樣子，然後從背後捅別人一刀，再踹一腳。不就是這些事情嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......대체 그동안 사장님께 제 평가 보고서가 어떻게 올라갔는지 궁금해지는 대목이네요.","JPN":"……今まで私に関して社長にどう報告されていたのか、すごく気になるところです。","ENG":"I'm curious to know what my performance reviews say about me.","TWN":"……我很好奇在這段時間，您交給老闆的評價報告書上，到底寫了什麼。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"부사장님.","JPN":"副社長？","ENG":"Vice President.","TWN":"副總。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"당연히 공정하고도 객관적인 기록의 바탕 위에,","JPN":"もちろん公正かつ客観的な記録に、","ENG":"The reviews were obviously written professionally with honest judgment,","TWN":"當然是根據公正且客觀的記錄……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"전문적이고도 심층적인 판단이 가미된 결과지.","JPN":"専門的で深層的な判断を加味した結果です。","ENG":"based upon just and objective records.","TWN":"加上專業又詳細的判斷後得出的結果。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그게 뭔데요?","JPN":"それは何ですか？","ENG":"What would that be?","TWN":"那是什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"글쎄? 도둑고양이?","JPN":"さあ？泥棒猫とか？","ENG":"Well? A stray cat?","TWN":"誰知道？流浪貓？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"하아...... 네 뭐, 솔직히 말하자면 하나같이 익숙한 것들이긴 하네요.","JPN":"はあ……まあ、正直なところ、どれも慣れています。","ENG":"*Sigh* Well, yeah. To be honest, that's all familiar to me.","TWN":"哈啊……好吧，說實話，這些我都很熟悉。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"블랙 네트워크에서 굴러먹으려면 솔직하고 착한 소녀 같은 건 별 도움이 안되거든요.","JPN":"素直で優しい少女では、ブラックネットワークで生き残れないので。","ENG":"If you want to survive in the Dark Network, being a good girl has no advantages.","TWN":"要在黑色網路中打滾，當一個誠實又善良的少女是沒有幫助的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그래서 시키실 일이 뭐죠?","JPN":"それで、任せたい仕事とは何ですか？","ENG":"So, what do you want me to do?","TWN":"所以，你想委託的事情是什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"누구 뒤통수를 치고 밥상에 재를 뿌리면 되는 건가요?","JPN":"誰を裏切って、破滅させるんですか？","ENG":"Who do I have to backstab and betray?","TWN":"要我在背後捅別人一刀嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 아주 잘 아는 사람이라네.","JPN":"君がよく知っている人物だ。","ENG":"It's someone you know very well.","TWN":"是妳非常熟悉的人。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"언제나 자네의 앞길에 지표가 되어 주는...... 등대 같은 사람이라고나 할까?","JPN":"いつも君の道しるべになってくれる……灯台のような人とでも言おうか？","ENG":"Someone who always guides your way... A lighthouse per se.","TWN":"總是指引妳前方的路途……應該可以說是像燈塔一樣的人吧？"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"당신, 어디까지 알고 있는 거야?","JPN":"どこまで知ってるんですか？","ENG":"How much do you know?","TWN":"您到底知道多少？"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 모르는 것까지 알고 있다고 말해 줄 수 있겠군.","JPN":"君が知らないことまで、すべて知っている。答えになったか？","ENG":"Let's just say I know more than you realize.","TWN":"可以說連妳不知道的事情我都知道吧。"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"참고로 남은 기록이 별로 없어서 조사하느라 꽤 힘들었네.","JPN":"ちなみに、残っている記録があまりなくて、調査がかなり大変だったんだ。","ENG":"It was difficult looking things up, since there weren't that many records left about you.","TWN":"順帶一提，留存下來的紀錄沒有多少，我調查花了不少力氣呢。"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그래서, 뭘 하면 되죠?","JPN":"それで、何をすればいいんですか？","ENG":"So, what do you want from me?","TWN":"所以，您想讓我做什麼？"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흥미가 생긴 모양이로군. 좋은 징조야.","JPN":"興味が湧いたようだな。いい兆しだ。","ENG":"Looks like I caught your attention. A good sign.","TWN":"看來妳產生興趣了，這是個好兆頭。"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자세한 내용은 메일로 전달해 놓겠네.","JPN":"詳しい内容はメールで送る。","ENG":"I'll send you a note with the details.","TWN":"詳細內容我會用郵件發給妳。"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"일이 끝나고 나면 성패에 관계없이 자네와 알트 소대 전원에게,","JPN":"この依頼を終えれば成否に関わらず、君とアルト小隊の全隊員に、","ENG":"Once the job is done, I will issue Official Administration Licenses","TWN":"這份工作結束後，無論成敗如何，我都會給妳和阿爾特小隊全員……"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관리국 정식 라이선스를 발급해 주도록 하지.","JPN":"管理局の正式ライセンスを発行しよう。","ENG":"to you and the entire ALT Squad, regardless of the result.","TWN":"發行管理局的正式執照。"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"라이선스를......?","JPN":"ライセンスを……？","ENG":"The licenses?","TWN":"執照……？"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그런 걸 일개 태스크포스 사장이 마음대로 발급할 수 있을 리가 없잖아요?","JPN":"そんなの、一介のタスクフォースカンパニーの社長が勝手に発行できるはずがないじゃないですか。","ENG":"How can a mere TASKFORCE CEO decide whether or not licenses can be issued?","TWN":"這種東西，一個特遣勢力的老闆是不可能隨便發行的吧？"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"사장님 대체 정체가 뭐죠?","JPN":"……社長は一体何者ですか？","ENG":"Who are you really?","TWN":"老闆的真實身分到底是？"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그야 사원들이 꿈을 이룰 수 있도록 무대 뒤에서 열심히 응원하는,","JPN":"社員たちが夢を叶えられるよう、舞台裏で一生懸命応援する、","ENG":"Well, I'm just a reliable helper who is cheering on all of the employees","TWN":"當然是讓員工的夢想能夠實現，在舞台後幫他們熱情加油的……"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"믿음직한 조력자지.","JPN":"頼もしいサポーターだ。","ENG":"from backstage.","TWN":"可靠幫助者。"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"확실히 구미가 당기는 제안이네요.","JPN":"確かに魅力的な提案です。","ENG":"That is definitely an appealing offer.","TWN":"這確實是個很有吸引力的提案。"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"하지만 그만큼 위험한 일이겠죠?","JPN":"でもその分、危険なんですよね？","ENG":"But I suppose it'll be dangerous?","TWN":"但相對的，也是件危險的工作吧？"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"약간의 난관들이 도사리고 있긴 하지.","JPN":"多少のリスクがないわけではない。","ENG":"There are some obstacles waiting for you.","TWN":"是會有一些難關阻撓。"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 세상 어떤 일이 그저 편하기만 하겠나?","JPN":"だが、仕事というのはそういうものだ。","ENG":"But there are no easy jobs in this world.","TWN":"但是這個世上哪會有這麼輕鬆的好事？"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"추가로 자네의 업무 의욕을 고취시키기 위해 한 가지 보상을 더 준비해 두었네.","JPN":"ちなみに、君のモチベーションを高めるために、もう一つ報酬を用意した。","ENG":"By the way, in order to boost your motivation, I prepared an additional reward.","TWN":"為了更加提高妳的工作意願，我還準備了一個獎勵。"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그게...... 뭐죠?","JPN":"それは……何ですか？","ENG":"What... would that be?","TWN":"那是……什麼？"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"리플레이서에게 납치되기 전, 자네의 과거 행적.","JPN":"リプレイサーに拉致される前の、君の過去だ。","ENG":"Your past before you were kidnapped by the Replacer Syndicate.","TWN":"在被克隆集團綁架之前，妳過去的行跡。"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......!!","JPN":"……！！","ENG":"......!!","TWN":"……！！"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아까도 말했듯이 이걸 찾아내느라 아주 힘들었어.","JPN":"さっきも言ったように、これを調べるのは本当に大変だった。","ENG":"Like I said, it was really hard to dig this up.","TWN":"正如我之前所說，這花了我不少力氣呢。"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 자네에겐 분명 의미가 있는 내용이겠지.","JPN":"だが、きっと君には意味がある内容だろう。","ENG":"But I'm sure it holds a special meaning to you.","TWN":"不過對妳來說，這個內容肯定很有意義吧。"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어떤가? 해 볼 텐가?","JPN":"どうだ？引き受けるか？","ENG":"What do you say? Will you do it?","TWN":"怎麼樣？要做做看嗎？"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"알겠습니다, 사장님.","JPN":"わかりました、社長。","ENG":"Very well, Boss.","TWN":"我知道了，老闆。"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"뭐든 분부만 내리시죠.","JPN":"何なりとお申し付けください。","ENG":"As you command.","TWN":"您儘管吩咐吧。"},"stage":{"bg":"HOSPITAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};